declare(strict_types=1);require __DIR__.'/../includes/bootstrap.php';require_role('finance');$page_title='Finance Reports - SMIS';$rows=db_all('SELECT COALESCE(fc.status,"pending") status,COUNT(*) total FROM students s LEFT JOIN finance_clearance fc ON fc.student_id=s.id GROUP BY COALESCE(fc.status,"pending")');include __DIR__.'/../includes/header.php';?><div class="page-header"><h1>Finance Reports</h1><p>Summary of student payment and financial clearance status.</p></div><div class="grid grid-col-3"><?php foreach($rows as $r):?><div class="stat-card"><div class="stat-card-value"><?=$r['total']?></div><div class="stat-card-label"><?=e(str_replace('_',' ',$r['status']))?> students</div></div><?php endforeach?></div><div class="card"><div class="card-body"><a class="btn btn-primary" href="<?=url('finance/students.php')?>">View all students</a></div></div><?php include __DIR__.'/../includes/footer.php';?>
